"""
Voice API Routes - Speech-to-Text and Text-to-Speech
"""

from flask import Blueprint, request, jsonify, send_file
import logging
import os
from werkzeug.utils import secure_filename
import tempfile
from pathlib import Path

logger = logging.getLogger(__name__)

voice_bp = Blueprint('voice', __name__, url_prefix='/api/voice')

# Allowed audio file extensions
ALLOWED_EXTENSIONS = {'wav', 'mp3', 'mp4', 'mpeg', 'mpga', 'm4a', 'webm', 'ogg'}

def allowed_file(filename):
    """Check if file extension is allowed"""
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@voice_bp.route('/transcribe', methods=['POST'])
def transcribe_audio():
    """
    Transcribe audio to text using OpenAI Whisper
    
    Request: multipart/form-data with 'audio' file
    Response: JSON with transcribed text
    """
    try:
        # Check if audio file is present
        if 'audio' not in request.files:
            return jsonify({
                'success': False,
                'error': 'No audio file provided',
                'text': ''
            }), 400
        
        audio_file = request.files['audio']
        
        if audio_file.filename == '':
            return jsonify({
                'success': False,
                'error': 'Empty filename',
                'text': ''
            }), 400
        
        if not allowed_file(audio_file.filename):
            return jsonify({
                'success': False,
                'error': f'Invalid file type. Allowed: {", ".join(ALLOWED_EXTENSIONS)}',
                'text': ''
            }), 400
        
        # Get language parameter (optional)
        language = request.form.get('language', 'en')
        
        # Save temporary file
        filename = secure_filename(audio_file.filename)
        temp_dir = Path(tempfile.gettempdir()) / "spicmacay_uploads"
        temp_dir.mkdir(exist_ok=True)
        
        temp_path = temp_dir / f"upload_{os.urandom(8).hex()}_{filename}"
        audio_file.save(str(temp_path))
        
        logger.info(f"Audio file uploaded: {temp_path} ({temp_path.stat().st_size} bytes)")
        
        # Transcribe using voice service
        from app import voice_service
        result = voice_service.transcribe_audio(str(temp_path), language)
        
        # Clean up uploaded file
        try:
            temp_path.unlink()
        except Exception as e:
            logger.warning(f"Could not delete temp file: {e}")
        
        return jsonify(result)
        
    except Exception as e:
        logger.error(f"Error in transcribe endpoint: {e}", exc_info=True)
        return jsonify({
            'success': False,
            'error': str(e),
            'text': ''
        }), 500

@voice_bp.route('/speak', methods=['POST'])
def text_to_speech():
    """
    Convert text to speech using OpenAI TTS
    
    Request: JSON with 'text', optional 'voice' and 'speed'
    Response: JSON with audio file URL
    """
    try:
        data = request.get_json()
        
        if not data or 'text' not in data:
            return jsonify({
                'success': False,
                'error': 'No text provided'
            }), 400
        
        text = data['text']
        voice = data.get('voice', 'nova')  # alloy, echo, fable, onyx, nova, shimmer
        speed = data.get('speed', 1.0)
        
        # Validate parameters
        if not text or len(text.strip()) == 0:
            return jsonify({
                'success': False,
                'error': 'Empty text'
            }), 400
        
        if len(text) > 4096:
            return jsonify({
                'success': False,
                'error': 'Text too long (max 4096 characters)'
            }), 400
        
        valid_voices = ['alloy', 'echo', 'fable', 'onyx', 'nova', 'shimmer']
        if voice not in valid_voices:
            voice = 'nova'
        
        # Generate speech
        from app import voice_service
        result = voice_service.text_to_speech(text, voice, speed)
        
        if result['success']:
            # Return URL to download audio
            result['audio_url'] = f"/api/voice/audio/{result['audio_filename']}"
        
        return jsonify(result)
        
    except Exception as e:
        logger.error(f"Error in text_to_speech endpoint: {e}", exc_info=True)
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

@voice_bp.route('/audio/<filename>', methods=['GET'])
def get_audio_file(filename):
    """
    Serve generated audio file
    
    Args:
        filename: Name of the audio file
        
    Response: Audio file (MP3)
    """
    try:
        # Security: validate filename
        if not filename.endswith('.mp3') or '..' in filename or '/' in filename:
            return jsonify({'error': 'Invalid filename'}), 400
        
        from app import voice_service
        audio_path = voice_service.temp_dir / filename
        
        if not audio_path.exists():
            return jsonify({'error': 'Audio file not found'}), 404
        
        return send_file(
            str(audio_path),
            mimetype='audio/mpeg',
            as_attachment=False,
            download_name=filename
        )
        
    except Exception as e:
        logger.error(f"Error serving audio file: {e}", exc_info=True)
        return jsonify({'error': str(e)}), 500

