@voice_bp.route('/cleanup', methods=['POST'])
def cleanup_old_files():
    """
    Manually trigger cleanup of old audio files
    Admin endpoint
    """
    try:
        max_age = request.json.get('max_age_hours', 24) if request.json else 24
        
        from app import voice_service
        voice_service.cleanup_old_files(max_age)
        
        return jsonify({
            'success': True,
            'message': f'Cleaned up files older than {max_age} hours'
        })
        
    except Exception as e:
        logger.error(f"Error in cleanup endpoint: {e}", exc_info=True)
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500
